/// <summary>
/// Bin qty status chart visual representation helper class 
/// </summary>
public class ETGBinQtyVisualChartHelperClass
{
}

Method.Source:
public static void populateBinQtyChartData(InventDim inventDim,FormPartControl formpartcontrol,DataAreaId _dataAreaId = null)
{
    WMSLocation                 location;
    FormRun                     formPartRun = formpartcontrol.getPartFormRun();
    FormDataSource              formDs;
    ETGBINAvailableQtyTable     binTable;

    if(_dataAreaId)
    {
        location = WMSLocation::findInLegalEntity(inventDim.wMSLocationId,inventDim.InventLocationId,_dataAreaId);
    }
    else
    {
        location = WMSLocation::find(inventDim.wMSLocationId,inventDim.InventLocationId);
    }

    delete_from binTable;

    if(location)
    {
        bintable.BINName = location.wMSLocationId;
        bintable.AvailableQty = location.freeVolume();
        bintable.CurrentQty = location.maxVolume - bintable.AvailableQty;
        bintable.TotalQty = location.maxVolume;
        bintable.insert();
    }

    if(formPartRun)
    {
        formDs = formPartRun.dataSource(formDataSourceStr(ETGBinVolumeAvailableChartForm, ETGBINAvailableQtyTable));
        if(formDs)
        {
            formDs.research(true);
            formDs.refresh();
        }
    }
}
